# Generated by openai (gpt-5.2)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
  agent any

  options {
    timestamps()
    disableConcurrentBuilds()
    buildDiscarder(logRotator(numToKeepStr: '30', artifactNumToKeepStr: '10'))
    timeout(time: 60, unit: 'MINUTES')
  }

  parameters {
    choice(
      name: 'ARTIFACT_TYPE',
      choices: ['single', 'zip', 'tar', 'tgz'],
      description: 'How to unpack/deploy the downloaded artifact.'
    )
    string(
      name: 'ARTIFACT_URL',
      defaultValue: '',
      trim: true,
      description: 'External URL to pre-built artifact (https/http, s3://bucket/key, artifactory URL).'
    )
    string(
      name: 'ARTIFACT_NAME',
      defaultValue: '',
      trim: true,
      description: 'Optional output filename (e.g., app.zip). If empty, derived from URL.'
    )
    string(
      name: 'ARTIFACT_SHA256',
      defaultValue: '',
      trim: true,
      description: 'Optional SHA256 checksum to verify downloaded artifact.'
    )
    booleanParam(
      name: 'ALLOW_INSECURE_TLS',
      defaultValue: false,
      description: 'Allow insecure TLS (curl -k).'
    )
    string(
      name: 'DEPLOY_USER',
      defaultValue: 'deploy',
      trim: true,
      description: 'SSH user for production servers.'
    )
    text(
      name: 'PROD_SERVERS',
      defaultValue: 'prod1.example.com\nprod2.example.com',
      description: 'One hostname/IP per line.'
    )
    string(
      name: 'REMOTE_DEPLOY_DIR',
      defaultValue: '/opt/app',
      trim: true,
      description: 'Remote deployment directory.'
    )
    string(
      name: 'REMOTE_RELEASES_DIR',
      defaultValue: '/opt/app/releases',
      trim: true,
      description: 'Remote releases directory (for unpacked deployments).'
    )
    string(
      name: 'REMOTE_CURRENT_SYMLINK',
      defaultValue: '/opt/app/current',
      trim: true,
      description: 'Remote symlink to current release.'
    )
    string(
      name: 'SERVICE_NAME',
      defaultValue: '',
      trim: true,
      description: 'Optional systemd service to restart after deploy.'
    )
    booleanParam(
      name: 'RESTART_SERVICE',
      defaultValue: true,
      description: 'Restart service after deployment (if SERVICE_NAME is set).'
    )
    booleanParam(
      name: 'DRY_RUN',
      defaultValue: false,
      description: 'If true, do not change remote servers.'
    )
    credentials(
      name: 'HTTP_BASIC_CREDENTIALS',
      defaultValue: '',
      description: 'Optional username/password for HTTP(S) download (Basic auth).'
    )
    credentials(
      name: 'SSH_CREDENTIALS',
      defaultValue: '',
      description: 'SSH private key credentials for deploying to production servers.'
    )
    credentials(
      name: 'AWS_CREDENTIALS',
      defaultValue: '',
      description: 'Optional AWS credentials (Access Key/Secret) for s3:// downloads.'
    )
  }

  environment {
    WORK_DIR = "${env.WORKSPACE}/_artifact"
    DOWNLOAD_DIR = "${env.WORKSPACE}/_download"
    STAGING_DIR = "${env.WORKSPACE}/_staging"
  }

  stages {
    stage('Validate') {
      steps {
        script {
          if (!params.ARTIFACT_URL?.trim()) {
            error('ARTIFACT_URL is required.')
          }
          if (!params.PROD_SERVERS?.trim()) {
            error('PROD_SERVERS is required.')
          }
          def servers = params.PROD_SERVERS.split('\n').collect { it.trim() }.findAll { it }
          if (servers.isEmpty()) {
            error('PROD_SERVERS must contain at least one server.')
          }
          env._SERVERS = servers.join(' ')
        }
      }
    }

    stage('Prepare Workspace') {
      steps {
        sh """
          set -euo pipefail
          rm -rf "${WORK_DIR}" "${DOWNLOAD_DIR}" "${STAGING_DIR}"
          mkdir -p "${WORK_DIR}" "${DOWNLOAD_DIR}" "${STAGING_DIR}"
        """
      }
    }

    stage('Download Artifact') {
      steps {
        script {
          def url = params.ARTIFACT_URL.trim()
          def inferredName = url.tokenize('/').last()
          if (!inferredName) inferredName = 'artifact.bin'
          def outName = params.ARTIFACT_NAME?.trim() ? params.ARTIFACT_NAME.trim() : inferredName
          env.ARTIFACT_FILE = "${DOWNLOAD_DIR}/${outName}"

          def isS3 = url.toLowerCase().startsWith('s3://')
          def isHttp = url.toLowerCase().startsWith('http://') || url.toLowerCase().startsWith('https://')

          if (!isS3 && !isHttp) {
            error("Unsupported ARTIFACT_URL scheme. Use http(s):// or s3:// . Got: ${url}")
          }

          if (isS3) {
            if (!params.AWS_CREDENTIALS?.trim()) {
              error('AWS_CREDENTIALS is required for s3:// downloads.')
            }
            withCredentials([usernamePassword(credentialsId: params.AWS_CREDENTIALS, usernameVariable: 'AWS_ACCESS_KEY_ID', passwordVariable: 'AWS_SECRET_ACCESS_KEY')]) {
              sh """
                set -euo pipefail
                export AWS_ACCESS_KEY_ID="\$AWS_ACCESS_KEY_ID"
                export AWS_SECRET_ACCESS_KEY="\$AWS_SECRET_ACCESS_KEY"
                export AWS_DEFAULT_REGION="\${AWS_DEFAULT_REGION:-us-east-1}"
                command -v aws >/dev/null 2>&1 || { echo "aws CLI not found"; exit 2; }
                aws s3 cp "${url}" "${ARTIFACT_FILE}"
              """
            }
          } else {
            def insecure = params.ALLOW_INSECURE_TLS ? '-k' : ''
            if (params.HTTP_BASIC_CREDENTIALS?.trim()) {
              withCredentials([usernamePassword(credentialsId: params.HTTP_BASIC_CREDENTIALS, usernameVariable: 'HTTP_USER', passwordVariable: 'HTTP_PASS')]) {
                sh """
                  set -euo pipefail
                  command -v curl >/dev/null 2>&1 || { echo "curl not found"; exit 2; }
                  curl -fL ${insecure} -u "\$HTTP_USER:\$HTTP_PASS" -o "${ARTIFACT_FILE}" "${url}"
                """
              }
            } else {
              sh """
                set -euo pipefail
                command -v curl >/dev/null 2>&1 || { echo "curl not found"; exit 2; }
                curl -fL ${insecure} -o "${ARTIFACT_FILE}" "${url}"
              """
            }
          }

          sh """
            set -euo pipefail
            ls -lah "${ARTIFACT_FILE}"
          """
        }
      }
    }

    stage('Verify Checksum') {
      when {
        expression { return params.ARTIFACT_SHA256?.trim() }
      }
      steps {
        sh """
          set -euo pipefail
          command -v sha256sum >/dev/null 2>&1 || { echo "sha256sum not found"; exit 2; }
          echo "${params.ARTIFACT_SHA256.trim()}  ${ARTIFACT_FILE}" | sha256sum -c -
        """
      }
    }

    stage('Stage Artifact') {
      steps {
        script {
          def t = params.ARTIFACT_TYPE
          sh """
            set -euo pipefail
            rm -rf "${STAGING_DIR:?}"/*
            mkdir -p "${STAGING_DIR}"
          """
          if (t == 'single') {
            sh """
              set -euo pipefail
              cp -f "${ARTIFACT_FILE}" "${STAGING_DIR}/"
            """
          } else if (t == 'zip') {
            sh """
              set -euo pipefail
              command -v unzip >/dev/null 2>&1 || { echo "unzip not found"; exit 2; }
              unzip -q "${ARTIFACT_FILE}" -d "${STAGING_DIR}"
            """
          } else if (t == 'tar') {
            sh """
              set -euo pipefail
              tar -xf "${ARTIFACT_FILE}" -C "${STAGING_DIR}"
            """
          } else if (t == 'tgz') {
            sh """
              set -euo pipefail
              tar -xzf "${ARTIFACT_FILE}" -C "${STAGING_DIR}"
            """
          } else {
            error("Unknown ARTIFACT_TYPE: ${t}")
          }

          sh """
            set -euo pipefail
            echo "Staged content:"
            (cd "${STAGING_DIR}" && find . -maxdepth 3 -type f -o -type l | sed 's#^./##' | head -n 200)
          """
        }
      }
    }

    stage('Deploy to Production') {
      steps {
        script {
          def servers = env._SERVERS.split(' ').collect { it.trim() }.findAll { it }
          def releaseId = new Date().format("yyyyMMddHHmmss", TimeZone.getTimeZone('UTC'))
          env.RELEASE_ID = releaseId

          if (!params.SSH_CREDENTIALS?.trim()) {
            error('SSH_CREDENTIALS is required for deployment.')
          }

          def dry = params.DRY_RUN ? 'true' : 'false'
          def service = params.SERVICE_NAME?.trim()
          def restart = (params.RESTART_SERVICE && service) ? 'true' : 'false'

          withCredentials([sshUserPrivateKey(credentialsId: params.SSH_CREDENTIALS, keyFileVariable: 'SSH_KEY', usernameVariable: 'SSH_USER_FROM_CRED')]) {
            def sshUser = params.DEPLOY_USER?.trim() ? params.DEPLOY_USER.trim() : (env.SSH_USER_FROM_CRED ?: 'deploy')
            sh """
              set -euo pipefail
              command -v rsync >/dev/null 2>&1 || { echo "rsync not found"; exit 2; }
              command -v ssh >/dev/null 2>&1 || { echo "ssh not found"; exit 2; }
            """

            for (s in servers) {
              sh """
                set -euo pipefail

                SERVER="${s}"
                SSH_OPTS="-i \\"$SSH_KEY\\" -o StrictHostKeyChecking=no -o UserKnownHostsFile=/dev/null"
                REMOTE_USER="${sshUser}"
                REMOTE_DEPLOY_DIR="${params.REMOTE_DEPLOY_DIR.trim()}"
                REMOTE_RELEASES_DIR="${params.REMOTE_RELEASES_DIR.trim()}"
                REMOTE_CURRENT="${params.REMOTE_CURRENT_SYMLINK.trim()}"
                RELEASE_ID="${releaseId}"
                DRY_RUN="${dry}"
                RESTART="${restart}"
                SERVICE_NAME="${service ?: ''}"

                if [ "\$DRY_RUN" = "true" ]; then
                  echo "[DRY_RUN] Would deploy to \$SERVER"
                  echo "[DRY_RUN] Would create release dir: \$REMOTE_RELEASES_DIR/\$RELEASE_ID"
                  echo "[DRY_RUN] Would rsync staged content to remote"
                  echo "[DRY_RUN] Would update symlink: \$REMOTE_CURRENT -> \$REMOTE_RELEASES_DIR/\$RELEASE_ID"
                  if [ "\$RESTART" = "true" ]; then
                    echo "[DRY_RUN] Would restart service: \$SERVICE_NAME"
                  fi
                  exit 0
                fi

                ssh \$SSH_OPTS "\$REMOTE_USER@\$SERVER" "set -euo pipefail; sudo mkdir -p '\$REMOTE_DEPLOY_DIR' '\$REMOTE_RELEASES_DIR'; sudo chown -R '\$REMOTE_USER':'\$REMOTE_USER' '\$REMOTE_DEPLOY_DIR' '\$REMOTE_RELEASES_DIR'"

                ssh \$SSH_OPTS "\$REMOTE_USER@\$SERVER" "set -euo pipefail; mkdir -p '\$REMOTE_RELEASES_DIR/\$RELEASE_ID'"

                rsync -az --delete -e "ssh \$SSH_OPTS" "${STAGING_DIR}/" "\$REMOTE_USER@\$SERVER:\$REMOTE_RELEASES_DIR/\$RELEASE_ID/"

                ssh \$SSH_OPTS "\$REMOTE_USER@\$SERVER" "set -euo pipefail; ln -sfn '\$REMOTE_RELEASES_DIR/\$RELEASE_ID' '\$REMOTE_CURRENT'"

                if [ "\$RESTART" = "true" ]; then
                  ssh \$SSH_OPTS "\$REMOTE_USER@\$SERVER" "set -euo pipefail; sudo systemctl restart '\$SERVICE_NAME'; sudo systemctl is-active --quiet '\$SERVICE_NAME'"
                fi

                echo "Deployed to \$SERVER release \$RELEASE_ID"
              """
            }
          }
        }
      }
    }
  }

  post {
    success {
      echo "Deployment completed. Release: ${env.RELEASE_ID ?: 'n/a'}"
    }
    failure {
      echo "Deployment failed."
    }
    always {
      sh """
        set +e
        rm -rf "${WORK_DIR}" "${DOWNLOAD_DIR}" "${STAGING_DIR}"
      """
    }
  }
}